mapper.select:
SELECT o.order_id, o.order_no, o.customer_id, o.business_id, o.bid_id, o.total_amount, o.payment_status, o.accept_status, o.delivery_status, o.created_at, c.nickname AS customer_nickname, b.company_name AS business_nickname FROM orders o JOIN customer c ON c.customer_id = o.customer_id LEFT JOIN business b ON b.business_id = o.business_id WHERE o.payment_status = 'PAID' AND o.bid_id IS NULL AND o.accept_status IN ('ACCEPTED', 'REJECTED')
AND c.login_id LIKE CONCAT('%', #{search.keyword}, '%')
AND c.nickname LIKE CONCAT('%', #{search.keyword}, '%')
AND c.phone_number LIKE CONCAT('%', #{search.keyword}, '%')
AND o.order_no LIKE CONCAT('%', #{search.keyword}, '%')
AND DATE(o.created_at) >= #{search.startDate}
AND DATE(o.created_at) <= #{search.endDate}
ORDER BY o.created_at DESC LIMIT #{limit} OFFSET #{offset}

mapper.delete:
DELETE FROM review
WHERE order_item_id IN (
    SELECT order_item_id FROM order_items WHERE order_id = #{orderId}
)

mapper.update:
UPDATE orders
SET customer_deleted = 1
WHERE order_id = #{orderId}

mapper.select:
SELECT o.order_id AS orderId, o.order_no AS orderNo, o.customer_id AS customerId, o.business_id AS businessId, o.bid_id AS bidId, o.total_amount AS totalAmount, o.payment_status AS paymentStatus, o.accept_status AS acceptStatus, o.delivery_status AS deliveryStatus, o.created_at AS createdAt,
c.nickname AS customerNickname, b.company_name AS businessNickname
FROM orders o LEFT JOIN business b ON b.business_id = o.business_id LEFT JOIN customer c ON c.customer_id = o.customer_id
WHERE o.payment_status = 'PAID' AND o.customer_deleted = 0 AND o.bid_id IS NULL
AND ( o.order_no LIKE CONCAT('%', #{search.keyword}, '%') OR c.nickname LIKE CONCAT('%', #{search.keyword}, '%') OR b.company_name LIKE CONCAT('%', #{search.keyword}, '%')
OR EXISTS ( SELECT 1 FROM order_items oi LEFT JOIN kit k ON k.kit_id = oi.kit_id LEFT JOIN bids bd ON bd.bid_id = o.bid_id LEFT JOIN request r ON r.request_id = bd.request_id WHERE oi.order_id = o.order_id AND ( k.name LIKE CONCAT('%', #{search.keyword}, '%') OR r.title LIKE CONCAT('%', #{search.keyword}, '%') ) ) )
AND DATE(o.created_at) >= #{search.startDate}
AND DATE(o.created_at) <= #{search.endDate}
ORDER BY o.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM orders o LEFT JOIN business b ON b.business_id = o.business_id LEFT JOIN customer c ON c.customer_id = o.customer_id
WHERE o.payment_status = 'PAID' AND o.customer_deleted = 0 AND o.bid_id IS NULL
AND ( o.order_no LIKE CONCAT('%', #{search.keyword}, '%') OR c.nickname LIKE CONCAT('%', #{search.keyword}, '%') OR b.company_name LIKE CONCAT('%', #{search.keyword}, '%')
OR EXISTS ( SELECT 1 FROM order_items oi LEFT JOIN kit k ON k.kit_id = oi.kit_id LEFT JOIN bids bd ON bd.bid_id = o.bid_id LEFT JOIN request r ON r.request_id = bd.request_id WHERE oi.order_id = o.order_id AND ( k.name LIKE CONCAT('%', #{search.keyword}, '%') OR r.title LIKE CONCAT('%', #{search.keyword}, '%') ) ) )
AND DATE(o.created_at) >= #{search.startDate}
AND DATE(o.created_at) <= #{search.endDate}
